class Solution {
public:
    bool checkSubarraySum(vector<int>& nums, int k) {
        unordered_map<int, int> prefix;
        prefix[0] = -1;
        int sum = 0;
        for (int i = 0; i < nums.size(); i++) {
            sum += nums[i];
            int mod = sum % k;
            if (prefix.find(mod) != prefix.end() && i - prefix[mod] >= 2) {
                return true;
            }
            if (prefix.find(mod) == prefix.end()) {
                prefix[mod] = i;
            }
        }
        return false;
    }
};
```

